DO $$
BEGIN
    IF (SELECT COUNT(*) FROM seed_participants) <> 460 THEN
        RAISE EXCEPTION 'Expected 460 seed participants, found %', (SELECT COUNT(*) FROM seed_participants);
    END IF;

    IF EXISTS (
        SELECT 1 FROM seed_participants GROUP BY id HAVING COUNT(*) > 1
    ) THEN
        RAISE EXCEPTION 'Duplicate participant IDs in seed_participants';
    END IF;

    IF EXISTS (
        SELECT 1
        FROM seed_participants
        WHERE claim_code IS NOT NULL
        GROUP BY claim_code
        HAVING COUNT(*) > 1
    ) THEN
        RAISE EXCEPTION 'Duplicate claim codes in seed_participants';
    END IF;
END $$;

INSERT INTO public.users (
    id, email, password_hash, first_name, last_name, phone_number, user_type
)
SELECT
    uuid_generate_v5('6ba7b811-9dad-11d1-80b4-00c04fd430c8'::UUID, 'nimun-2026:' || id),
    NULLIF(email, ''),
    crypt(id, gen_salt('bf', 10)),
    first_name,
    last_name,
    NULLIF(phone_number, ''),
    user_type
FROM seed_participants;

INSERT INTO public.delegates (
    id, user_id, council, claim_token, qr_code, status, award, past_awards
)
SELECT
    id,
    uuid_generate_v5('6ba7b811-9dad-11d1-80b4-00c04fd430c8'::UUID, 'nimun-2026:' || id),
    target_committee,
    NULLIF(claim_code, ''),
    id,
    CASE WHEN claim_code IS NULL THEN 'unclaimed' ELSE 'active' END,
    NULL,
    '{}'::TEXT[]
FROM seed_participants
WHERE participant_type = 'delegate';

INSERT INTO public.members (
    id, user_id, role, committee, claim_token, permissions, award, past_awards
)
SELECT
    id,
    uuid_generate_v5('6ba7b811-9dad-11d1-80b4-00c04fd430c8'::UUID, 'nimun-2026:' || id),
    role,
    target_committee,
    NULLIF(claim_code, ''),
    permissions,
    NULL,
    '{}'::TEXT[]
FROM seed_participants
WHERE participant_type = 'member';

INSERT INTO public.invitations (
    id, user_id, role, committee, claim_token, status
)
SELECT
    id,
    uuid_generate_v5('6ba7b811-9dad-11d1-80b4-00c04fd430c8'::UUID, 'nimun-2026:' || id),
    role,
    target_committee,
    NULLIF(claim_code, ''),
    'active'
FROM seed_participants
WHERE participant_type = 'invitation';

-- Verification summary
SELECT 'users' AS table_name, COUNT(*) AS count FROM public.users
UNION ALL SELECT 'delegates', COUNT(*) FROM public.delegates
UNION ALL SELECT 'members', COUNT(*) FROM public.members
UNION ALL SELECT 'invitations', COUNT(*) FROM public.invitations
ORDER BY table_name;

COMMIT;
